export type PinType = 'visto' | 'fatto' | 'raccolto' | 'offro';

export interface PinReactions {
  like: number;
  heart: number;
  comment: number;
}

export interface Pin {
  id: string;
  type: PinType;
  emoji: string;
  text: string;
  user: string;
  time: string;
  sentiment: 'positivo' | 'neutro' | 'urgente' | 'ispirante';
  reactions: PinReactions;
  tags: string[];
  x: number; // Percentage coordinate
  y: number; // Percentage coordinate
  rotation?: number;
}

export interface AreaAnalysis {
  zona: string;
  periodo: string;
  ratio_visto_fatto: string;
  utenti_catalizzatore: string[];
  picchi_orari: string[];
  temi_ricorrenti: string[];
  insight_principale: string;
  azione_consigliata: string;
  confronto_benchmark: string;
}

export interface ConnectionSuggestion {
  pin_A: string;
  pin_B: string;
  connessione: string;
  azione_suggerita: string;
  valore_generato: string;
}

export interface ChatMessage {
  role: 'user' | 'bot';
  content: string;
  isGenerating?: boolean;
}

import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_PROMPT } from "../constants";
import { Pin, AreaAnalysis, ConnectionSuggestion } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateSimulatedPins = async (scenario: string): Promise<Partial<Pin>[]> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Genera 5 post-it simulati basati su questo scenario: ${scenario}`,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              type: { type: Type.STRING },
              emoji: { type: Type.STRING },
              text: { type: Type.STRING },
              user: { type: Type.STRING },
              time: { type: Type.STRING },
              sentiment: { type: Type.STRING },
              reactions: {
                type: Type.OBJECT,
                properties: {
                  like: { type: Type.NUMBER },
                  heart: { type: Type.NUMBER },
                  comment: { type: Type.NUMBER }
                }
              },
              tags: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
              }
            },
            required: ["type", "text", "user", "time"]
          }
        }
      }
    });

    return JSON.parse(response.text || '[]');
  } catch (error) {
    console.error("Gemini Error:", error);
    return [];
  }
};

export const analyzeArea = async (pins: Pin[]): Promise<AreaAnalysis | null> => {
  try {
    const pinsSummary = pins.map(p => `${p.user}: ${p.text}`).join('\n');
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Analizza questi post-it e restituisci un'analisi di zona dettagliata:\n${pinsSummary}`,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            zona: { type: Type.STRING },
            periodo: { type: Type.STRING },
            ratio_visto_fatto: { type: Type.STRING },
            utenti_catalizzatore: { type: Type.ARRAY, items: { type: Type.STRING } },
            picchi_orari: { type: Type.ARRAY, items: { type: Type.STRING } },
            temi_ricorrenti: { type: Type.ARRAY, items: { type: Type.STRING } },
            insight_principale: { type: Type.STRING },
            azione_consigliata: { type: Type.STRING },
            confronto_benchmark: { type: Type.STRING }
          }
        }
      }
    });

    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    return null;
  }
};

export const chatWithAI = async (message: string, history: { role: string; content: string }[]): Promise<string> => {
  try {
    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: SYSTEM_PROMPT,
      },
    });

    // Simple implementation: Send message with context manually for now if chat.sendMessage history is tricky
    // Better: use the SDK's chat history management
    const response = await chat.sendMessage({ message });
    return response.text || "Mi dispiace, non sono riuscito a generare una risposta.";
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return "Errore nella comunicazione con il motore AI.";
  }
};

import React from 'react';
import { Pin, PinType } from '../types';
import { PIN_CONFIG } from '../constants';

interface PostItProps {
  pin: Pin;
  onReact: (id: string, type: 'like' | 'heart' | 'comment') => void;
  style?: React.CSSProperties;
}

const PostIt: React.FC<PostItProps> = ({ pin, onReact, style }) => {
  const config = PIN_CONFIG[pin.type];
  const rot = pin.rotation || 0;

  return (
    <div
      className="absolute w-44 sm:w-52 rounded-sm p-3 pb-4 cursor-pointer shadow-lg hover:shadow-2xl transition-all duration-200 hover:scale-105 animate-pop-in z-10 hover:z-50"
      style={{
        left: `${pin.x}%`,
        top: `${pin.y}%`,
        backgroundColor: config.color,
        transform: `rotate(${rot}deg)`,
        ...style
      }}
    >
      {/* Push-pin visual */}
      <div className="absolute -top-1.5 left-1/2 -translate-x-1/2 w-3 h-3 rounded-full bg-black/20 shadow-md"></div>

      <div className="font-mono-code text-[10px] uppercase tracking-widest opacity-60 mb-1.5">
        {config.emoji} {pin.type}
      </div>

      <div className="font-serif-display text-sm leading-snug text-black/80 mb-2 min-h-[3rem]">
        {pin.text}
      </div>

      <div className="flex items-center justify-between border-t border-black/5 pt-2">
        <span className="font-mono-code text-[10px] text-black/50 truncate max-w-[60%]">{pin.user}</span>
        <span className="font-mono-code text-[9px] text-black/40">{pin.time}</span>
      </div>

      <div className="mt-2 flex gap-1.5">
        <button 
          onClick={(e) => { e.stopPropagation(); onReact(pin.id, 'like'); }}
          className="text-[11px] bg-black/5 hover:bg-black/10 rounded-full px-2 py-0.5 transition-colors"
        >
          👍 {pin.reactions.like}
        </button>
        <button 
          onClick={(e) => { e.stopPropagation(); onReact(pin.id, 'heart'); }}
          className="text-[11px] bg-black/5 hover:bg-black/10 rounded-full px-2 py-0.5 transition-colors"
        >
          ❤️ {pin.reactions.heart}
        </button>
        <button 
          onClick={(e) => { e.stopPropagation(); onReact(pin.id, 'comment'); }}
          className="text-[11px] bg-black/5 hover:bg-black/10 rounded-full px-2 py-0.5 transition-colors"
        >
          💬 {pin.reactions.comment}
        </button>
      </div>
    </div>
  );
};

export default PostIt;

import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage } from '../types';
import { chatWithAI } from '../services/geminiService';

interface AIPanelProps {
  isOpen: boolean;
  onClose: () => void;
  onSimulatePins: (scenario: string) => void;
}

const AIPanel: React.FC<AIPanelProps> = ({ isOpen, onClose, onSimulatePins }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'bot', content: "Ciao! Sono il motore AI di GreenPin. Dimmi la zona che vuoi esplorare e cosa stai cercando di fare: generare post-it simulati, analizzare una community esistente, o affinare il concept della piattaforma. Parto subito." }
  ]);
  const [input, setInput] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    if (isOpen) scrollToBottom();
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userMsg }]);

    // Check if user is asking to generate pins specifically
    const isAskingToGen = userMsg.toLowerCase().includes('genera') || userMsg.toLowerCase().includes('simula');

    setMessages(prev => [...prev, { role: 'bot', content: '', isGenerating: true }]);

    const botResponse = await chatWithAI(userMsg, messages.map(m => ({ role: m.role, content: m.content })));

    setMessages(prev => {
      const filtered = prev.filter(m => !m.isGenerating);
      return [...filtered, { role: 'bot', content: botResponse }];
    });

    if (isAskingToGen) {
      onSimulatePins(userMsg);
    }
  };

  return (
    <div className={`fixed right-0 top-16 bottom-0 w-80 md:w-96 bg-[#1b2e22]/95 backdrop-blur-xl border-l border-[#95d5b2]/15 z-[80] flex flex-col transition-transform duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}>
      <div className="p-5 border-b border-[#95d5b2]/10 flex items-center justify-between">
        <h3 className="font-serif-display text-lg text-[#95d5b2]">✦ GreenPin AI</h3>
        <button onClick={onClose} className="text-[#5a7a65] hover:text-[#95d5b2] text-xl">&times;</button>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-3 rounded-xl text-sm leading-relaxed ${
              m.role === 'user' 
                ? 'bg-[#95d5b2]/10 text-[#f4f0e8] rounded-br-none' 
                : 'bg-[#2d6a4f]/40 border border-[#95d5b2]/15 text-[#b7e4c7] rounded-bl-none'
            }`}>
              {m.isGenerating ? (
                <div className="flex gap-1 py-1">
                  <div className="w-1.5 h-1.5 bg-[#95d5b2] rounded-full animate-bounce"></div>
                  <div className="w-1.5 h-1.5 bg-[#95d5b2] rounded-full animate-bounce [animation-delay:0.2s]"></div>
                  <div className="w-1.5 h-1.5 bg-[#95d5b2] rounded-full animate-bounce [animation-delay:0.4s]"></div>
                </div>
              ) : m.content}
            </div>
          </div>
        ))}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-4 border-t border-[#95d5b2]/10 flex gap-2">
        <textarea
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => { if(e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend(); } }}
          placeholder="Es: genera 5 post-it per un parco..."
          className="flex-1 bg-[#95d5b2]/5 border border-[#95d5b2]/20 rounded-lg p-2.5 text-sm text-[#f4f0e8] placeholder-[#5a7a65] outline-none focus:border-[#95d5b2]/50 resize-none"
          rows={2}
        />
        <button 
          onClick={handleSend}
          className="bg-[#95d5b2] text-[#1b2e22] rounded-lg px-4 hover:bg-[#b7e4c7] transition-all font-bold"
        >
          →
        </button>
      </div>
    </div>
  );
};

export default AIPanel;

import React, { useState, useEffect, useCallback } from 'react';
