import { generateSimulatedPins, analyzeArea } from './services/geminiService';

const INITIAL_PINS: Pin[] = [
  { 
    id: '1', type: 'offro', emoji: '🤝', text: 'Offro 5€ per chi porta scopa e sacchi al parcheggio di via Pigneto stasera.', 
    user: 'Marco V.', time: '12min fa', sentiment: 'ispirante', reactions: { like: 8, heart: 3, comment: 2 }, tags: ['#cleanup'], x: 44, y: 38, rotation: -2 
  },
  { 
    id: '2', type: 'visto', emoji: '👁', text: 'Ho visto Luca pulire il campetto ogni mattina. Qualcuno sa chi è?', 
    user: 'Anonimo #4412', time: '34min fa', sentiment: 'neutro', reactions: { like: 12, heart: 5, comment: 1 }, tags: ['#segnalazione'], x: 28, y: 55, rotation: 3 
  },
  { 
    id: '3', type: 'fatto', emoji: '💪', text: 'Ho portato 4 sacchi dal sottopassaggio. Servirebbero bidoni fissi.', 
    user: 'Giulia R.', time: '1h fa', sentiment: 'positivo', reactions: { like: 15, heart: 8, comment: 4 }, tags: ['#azione'], x: 62, y: 42, rotation: -1 
  }
];

const App: React.FC = () => {
  const [pins, setPins] = useState<Pin[]>(INITIAL_PINS);
  const [filter, setFilter] = useState<PinType | 'all'>('all');
  const [isAIOpen, setIsAIOpen] = useState(false);
  const [analysis, setAnalysis] = useState<AreaAnalysis | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newPinText, setNewPinText] = useState('');
  const [newPinType, setNewPinType] = useState<PinType>('visto');

  const filteredPins = pins.filter(p => filter === 'all' || p.type === filter);

  const handleReact = (id: string, type: 'like' | 'heart' | 'comment') => {
    setPins(prev => prev.map(p => {
      if (p.id === id) {
        return { ...p, reactions: { ...p.reactions, [type]: p.reactions[type] + 1 } };
      }
      return p;
    }));
  };

  const handleSimulate = async (scenario: string) => {
    const simulated = await generateSimulatedPins(scenario);
    const newPins: Pin[] = simulated.map((p, i) => ({
      id: `sim-${Date.now()}-${i}`,
      type: (p.type as PinType) || 'visto',
      emoji: p.emoji || '📌',
      text: p.text || '',
      user: p.user || 'AI Simulator',
      time: p.time || 'adesso',
      sentiment: (p.sentiment as any) || 'neutro',
      reactions: p.reactions || { like: 0, heart: 0, comment: 0 },
      tags: p.tags || [],
      x: 15 + Math.random() * 70,
      y: 10 + Math.random() * 75,
      rotation: Math.random() * 10 - 5
    }));
    setPins(prev => [...prev, ...newPins]);
  };

  const handleAnalyze = async () => {
    setIsAnalyzing(true);
    const result = await analyzeArea(pins);
    setAnalysis(result);
    setIsAnalyzing(false);

    // Auto-hide analysis after 15 seconds
    setTimeout(() => setAnalysis(null), 15000);
  };

  const addNewPin = () => {
    if (!newPinText.trim()) return;
    const newPin: Pin = {
      id: Date.now().toString(),
      type: newPinType,
      emoji: PIN_CONFIG[newPinType].emoji,
      text: newPinText,
      user: 'Tu',
      time: 'ora',
      sentiment: 'neutro',
      reactions: { like: 0, heart: 0, comment: 0 },
      tags: [],
      x: 20 + Math.random() * 60,
      y: 20 + Math.random() * 60,
      rotation: Math.random() * 6 - 3
