        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-[#95d5b2] rounded-tr-xl rounded-tl-xl rounded-bl-xl flex items-center justify-center -rotate-45">
            <span className="rotate-45 text-sm">📍</span>
          </div>
          <h1 className="font-serif-display text-xl tracking-tight">Green<span className="text-[#95d5b2] italic">Pin</span></h1>
        </div>

        <div className="hidden md:flex items-center gap-4">
          <span className="font-mono-code text-[10px] text-[#95d5b2] border border-[#95d5b2] px-3 py-1 rounded-full opacity-70">📍 Quartiere Pigneto, RM</span>
          <button 
            onClick={() => setIsAIOpen(true)}
            className="bg-transparent border border-[#95d5b2] text-[#95d5b2] hover:bg-[#95d5b2] hover:text-[#1b2e22] px-4 py-1.5 rounded-full font-bold text-xs transition-all"
          >
            ✦ AI Assistant
          </button>
        </div>

        <button 
          onClick={() => setIsAIOpen(!isAIOpen)}
          className="md:hidden text-[#95d5b2] text-2xl"
        >
          ✦
        </button>
      </header>

      <div className="flex flex-1 mt-16 relative">
        {/* Sidebar */}
        <aside className="w-56 bg-[#1b2e22]/90 backdrop-blur-md border-r border-[#95d5b2]/10 p-5 flex flex-col gap-6 z-50">
          <div>
            <h2 className="font-mono-code text-[10px] text-[#5a7a65] uppercase tracking-[0.2em] mb-4">Filtra per azione</h2>
