                className={`w-full flex items-center gap-3 p-2.5 rounded-xl text-sm transition-all ${filter === 'all' ? 'bg-[#95d5b2]/15 border border-[#95d5b2]/25' : 'hover:bg-[#95d5b2]/5'}`}
              >
                <div className="w-2.5 h-2.5 rounded-full bg-[#95d5b2]"></div>
                Tutti i post-it
              </button>
              {(Object.keys(PIN_CONFIG) as PinType[]).map(type => (
                <button 
                  key={type}
                  onClick={() => setFilter(type)}
                  className={`w-full flex items-center gap-3 p-2.5 rounded-xl text-sm transition-all ${filter === type ? 'bg-[#95d5b2]/15 border border-[#95d5b2]/25' : 'hover:bg-[#95d5b2]/5'}`}
                >
