              className="bg-[#1b2e22]/80 backdrop-blur px-5 py-2.5 rounded-full border border-[#95d5b2]/30 text-xs font-bold text-[#b7e4c7] hover:bg-[#2d6a4f] transition-all disabled:opacity-50"
            >
              {isAnalyzing ? '...' : '🔍 Analizza zona'}
            </button>
          </div>
        </main>

        <AIPanel 
          isOpen={isAIOpen} 
          onClose={() => setIsAIOpen(false)} 
          onSimulatePins={handleSimulate} 
        />
      </div>

      {/* Stats Bar */}
      <footer className="h-10 bg-[#1b2e22]/95 border-t border-[#95d5b2]/10 flex items-center px-6 gap-8 z-50">
        <div className="flex items-center gap-2 font-mono-code text-[10px] text-[#5a7a65]">
          <div className="w-1.5 h-1.5 rounded-full bg-[#95d5b2]"></div>
          {pins.length} post-it attivi
        </div>
        <div className="flex items-center gap-2 font-mono-code text-[10px] text-[#5a7a65]">
          <div className="w-1.5 h-1.5 rounded-full bg-[#ffd166]"></div>
          {pins.filter(p => p.type === 'fatto').length} azioni compiute
        </div>
        <div className="hidden md:flex items-center gap-2 font-mono-code text-[10px] text-[#5a7a65] ml-auto">
