        </div>
      </footer>

      {/* New Pin Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 backdrop-blur-sm bg-black/60">
          <div className="bg-[#1b2e22] border border-[#95d5b2]/20 rounded-3xl p-8 w-full max-w-md animate-pop-in">
