                      ? 'bg-[#95d5b2]/15 border-[#95d5b2] text-[#b7e4c7]' 
                      : 'border-[#95d5b2]/10 text-[#5a7a65] hover:bg-[#95d5b2]/5'
                  }`}
                >
                  <span className="text-xl">{PIN_CONFIG[type].emoji}</span>
                  {PIN_CONFIG[type].label}
                </button>
              ))}
            </div>

            <textarea 
              value={newPinText}
              onChange={(e) => setNewPinText(e.target.value)}
              placeholder="Cosa hai visto, fatto o di cosa hai bisogno?"
              className="w-full h-32 bg-[#95d5b2]/5 border border-[#95d5b2]/20 rounded-xl p-4 text-[#f4f0e8] placeholder-[#5a7a65] outline-none focus:border-[#95d5b2]/50 resize-none mb-6"
            />

            <div className="flex gap-3">
              <button 
                onClick={() => setIsModalOpen(false)}
                className="flex-1 py-3 border border-[#95d5b2]/20 rounded-xl text-[#5a7a65] font-bold hover:bg-white/5"
              >
                Annulla
              </button>
              <button 
                onClick={addNewPin}
                className="flex-[2] py-3 bg-[#95d5b2] text-[#1b2e22] rounded-xl font-bold hover:bg-[#b7e4c7]"
              >
                Pubblica post-it
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

