import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_PROMPT } from "../constants";
import { Pin, AreaAnalysis, ConnectionSuggestion } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateSimulatedPins = async (scenario: string): Promise<Partial<Pin>[]> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Genera 5 post-it simulati basati su questo scenario: ${scenario}`,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              type: { type: Type.STRING },
              emoji: { type: Type.STRING },
              text: { type: Type.STRING },
              user: { type: Type.STRING },
              time: { type: Type.STRING },
              sentiment: { type: Type.STRING },
              reactions: {
                type: Type.OBJECT,
                properties: {
                  like: { type: Type.NUMBER },
                  heart: { type: Type.NUMBER },
                  comment: { type: Type.NUMBER }
                }
              },
              tags: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
              }
            },
            required: ["type", "text", "user", "time"]
          }
        }
      }
    });

    return JSON.parse(response.text || '[]');
  } catch (error) {
    console.error("Gemini Error:", error);
    return [];
  }
};

export const analyzeArea = async (pins: Pin[]): Promise<AreaAnalysis | null> => {
  try {
    const pinsSummary = pins.map(p => `ID:${p.id} [${p.user}]: ${p.text}`).join('\n');
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Analizza questi post-it e restituisci un'analisi di zona dettagliata:\n${pinsSummary}`,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            zona: { type: Type.STRING },
            periodo: { type: Type.STRING },
            ratio_visto_fatto: { type: Type.STRING },
            utenti_catalizzatore: { type: Type.ARRAY, items: { type: Type.STRING } },
            picchi_orari: { type: Type.ARRAY, items: { type: Type.STRING } },
            temi_ricorrenti: { type: Type.ARRAY, items: { type: Type.STRING } },
            insight_principale: { type: Type.STRING },
            azione_consigliata: { type: Type.STRING },
            confronto_benchmark: { type: Type.STRING }
          }
        }
      }
    });

    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    return null;
  }
};

export const suggestConnections = async (pins: Pin[]): Promise<ConnectionSuggestion[]> => {
  try {
    const pinsSummary = pins.map(p => `ID:${p.id} [${p.user}]: ${p.text}`).join('\n');
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Trova 2-3 possibili connessioni tra questi post-it (es: qualcuno offre aiuto e qualcuno ha un bisogno):\n${pinsSummary}`,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              pin_A: { type: Type.STRING, description: "ID del primo pin" },
              pin_B: { type: Type.STRING, description: "ID del secondo pin" },
              connessione: { type: Type.STRING },
              azione_suggerita: { type: Type.STRING },
              valore_generato: { type: Type.STRING }
            }
          }
        }
      }
    });

    return JSON.parse(response.text || '[]');
  } catch (error) {
    console.error("Gemini Connection Error:", error);
    return [];
  }
};

export const chatWithAI = async (message: string, history: { role: string; content: string }[]): Promise<string> => {
  try {
    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: SYSTEM_PROMPT,
      },
    });
    const response = await chat.sendMessage({ message });
    return response.text || "Mi dispiace, non sono riuscito a generare una risposta.";
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return "Errore nella comunicazione con il motore AI.";
  }
};

