// Componente per renderizzare il Post-it come marker Leaflet
const PostItMarker = ({ pin, onReact }: { pin: Pin, onReact: any }) => {
  const config = PIN_CONFIG[pin.type];
  const rot = pin.rotation || 0;

  const html = `
    <div class="w-48 p-3 pb-4 shadow-xl animate-pop-in" style="background-color: ${config.color}; transform: rotate(${rot}deg); pointer-events: auto;">
      <div class="absolute -top-1.5 left-1/2 -translate-x-1/2 w-3 h-3 rounded-full bg-black/20"></div>
      <div class="font-mono text-[9px] uppercase tracking-widest opacity-60 mb-1">${config.emoji} ${pin.type}</div>
      <div class="font-serif text-[13px] leading-tight text-black/80 mb-2">${pin.text}</div>
      <div class="flex justify-between border-t border-black/5 pt-1.5 font-mono text-[9px] text-black/40">
        <span>${pin.user}</span>
        <span>${pin.time}</span>
      </div>
    </div>
  `;

  const icon = L.divIcon({
    className: 'custom-postit-icon',
    html: html,
    iconSize: [200, 100],
    iconAnchor: [100, 50]
  });

  return (
    <Marker 
      position={[pin.lat, pin.lng]} 
      icon={icon}
      eventHandlers={{
        click: () => onReact(pin.id, 'like')
      }}
    />
  );
};

