const MapController = ({ analysis }: { analysis: any }) => {
  const map = useMap();
  useEffect(() => {
    if (analysis) {
       // Se c'è un'analisi, zooma leggermente per enfasi
       map.flyTo(FOGGIA_COORDS, 15, { duration: 1.5 });
    }
  }, [analysis]);
  return null;
};

