export interface PinReactions {
  like: number;
  heart: number;
  comment: number;
}

export interface Pin {
  id: string;
  type: PinType;
  emoji: string;
  text: string;
  user: string;
  time: string;
  sentiment: 'positivo' | 'neutro' | 'urgente' | 'ispirante';
