        // Handle potentially undefined x and y coordinates with fallback positioning
        left: pin.x !== undefined ? `${pin.x}%` : '0%',
        top: pin.y !== undefined ? `${pin.y}%` : '0%',
        backgroundColor: config.color,
        transform: `rotate(${rot}deg)`,
        ...style
