// Funzione per "staccare" i pin che hanno le stesse coordinate
const applyJitter = (pins: Pin[]): Pin[] => {
  const coordCount: Record<string, number> = {};
  return pins.map(pin => {
    const key = `${pin.lat.toFixed(6)},${pin.lng.toFixed(6)}`;
    const count = coordCount[key] || 0;
    coordCount[key] = count + 1;

    if (count === 0) return pin;

    // Applica un offset a spirale per staccarli visivamente
    const angle = count * 0.5;
    const offset = 0.0001 * count;
    return {
      ...pin,
      lat: pin.lat + Math.cos(angle) * offset,
      lng: pin.lng + Math.sin(angle) * offset
    };
  });
};

