const MapPicker = ({ onPositionChange }: { onPositionChange: (latlng: [number, number]) => void }) => {
  useMapEvents({
    move: (e) => {
      const center = e.target.getCenter();
      onPositionChange([center.lat, center.lng]);
    }
  });
  return null;
};

