    const loadCitySignals = async () => {
      setIsLiveLoading(true);
      const saved = localStorage.getItem(STORAGE_KEY);
      let initialPins = saved ? JSON.parse(saved) : [];

      const liveSignals = await fetchRealTimeCitySignals();
      const mappedSignals: Pin[] = liveSignals.map((s, i) => ({
        ...s,
        id: `live-${Date.now()}-${i}`,
        authorId: 'city-feed',
        sentiment: s.sentiment || 'neutro',
        reactions: { like: Math.floor(Math.random()*10), heart: 0, comment: 0 },
        tags: [],
        rotation: Math.random() * 6 - 3
      } as Pin));

      setPins([...initialPins, ...mappedSignals]);
      setIsLiveLoading(false);
    };

    loadCitySignals();
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(pins));
  }, [pins]);

  const handleSave = () => {
    if (!formText.trim() || !formAddress.trim()) return;

    if (editingId) {
      setPins(prev => prev.map(p => p.id === editingId ? {
        ...p,
        text: formText,
        address: formAddress,
        type: formType,
        emoji: PIN_CONFIG[formType].emoji
