              </div>

              <div className="flex gap-3">
                <button onClick={() => setIsModalOpen(false)} className="flex-1 py-5 font-bold text-gray-400 text-[10px] uppercase">Chiudi</button>
                <button onClick={handleSave} className="flex-[3] py-5 bg-[#1b2e22] text-white font-bold rounded-[2rem] shadow-xl hover:bg-[#2d6a4f] transition-all active:scale-95 uppercase text-[10px] tracking-widest">
